import Anthropic from "@anthropic-ai/sdk";
const client = new Anthropic();

async function extractEntities(text) {
  const resp = await client.messages.create({
    model: "claude-haiku-4-5",
    max_tokens: 256,
    system:
      "Extract all named entities from the text inside <text> tags. " +
      "Return ONLY a JSON array of strings. No other text.",
    messages: [{ role: "user", content: `<text>${text}</text>` }],
  });
  return JSON.parse(resp.content[0].text);
}

async function classifyEntities(entities) {
  const resp = await client.messages.create({
    model: "claude-haiku-4-5",
    max_tokens: 512,
    system:
      "Classify each entity in the JSON array as PERSON, ORG, or LOCATION. " +
      'Return ONLY a JSON array of { "entity": "...", "type": "..." } objects.',
    messages: [
      { role: "user", content: JSON.stringify(entities) },
    ],
  });
  return JSON.parse(resp.content[0].text);
}

const text =
  "Satya Nadella announced that Microsoft will open a new campus in London.";

const entities = await extractEntities(text);
console.log("Extracted:", entities);
// ["Satya Nadella", "Microsoft", "London"]

const classified = await classifyEntities(entities);
console.log("Classified:", classified);
// [
//   { entity: "Satya Nadella", type: "PERSON" },
//   { entity: "Microsoft",     type: "ORG"    },
//   { entity: "London",        type: "LOCATION" }
// ]
